{"version":3,"names":["_caching","require","fs","_fs2","data","makeStaticFileCache","fn","makeStrongCache","filepath","cache","cached","invalidate","fileMtime","readFile","nodeFs","existsSync","statSync","mtime","e","code"],"sources":["../../../src/config/files/utils.ts"],"sourcesContent":["import type { Handler } from "gensync";

import { makeStrongCache } from "../caching.ts";
import type { CacheConfigurator } from "../caching.ts";
import * as fs from "../../gensync-utils/fs.ts";
import nodeFs from "node:fs";

export function makeStaticFileCache<T>(
  fn: (filepath: string, contents: string) => T,
) {
  return makeStrongCache(function* (
    filepath: string,
    cache: CacheConfigurator<void>,
  ): Handler<null | T> {
    const cached = cache.invalidate(() => fileMtime(filepath));

    if (cached === null) {
      return null;
    }

    return fn(filepath, yield* fs.readFile(filepath, "utf8"));
  });
}

function fileMtime(filepath: string): number | null {
  if (!nodeFs.existsSync(filepath)) return null;

  try {
    return +nodeFs.statSync(filepath).mtime;
  } catch (e) {
    if (e.code !== "ENOENT" && e.code !== "ENOTDIR") throw e;
  }

  return null;
}
