    result: RegExpExecArray,
    re: RegExp,
  ): Record<string, string>;
  function buildGroups(
    result: RegExpIndicesArray,
    re: RegExp,
  ): Record<string, [number, number]>;
  function buildGroups(
    result: RegExpExecArray | RegExpIndicesArray,
    re: RegExp,
