    // calls `.pushContext`.
    return NodePath.get({
      parentPath,
      parent: node,
      container,
      key: key,
      listKey,
      hub,
    });
  }

  maybeQueue(path: NodePath, notPriority?: boolean) {
    if (this.queue) {
      if (notPriority) {
        this.queue.push(path);
      } else {
